// Extract and validate case details
const input = $input.first().json;
const errors = [];

if (!input.case_id && !input.matter_id) errors.push('Missing case/matter ID');
if (!input.client) errors.push('Missing client name');
if (!input.description && !input.case_type) errors.push('Missing case description or type');

// Normalize phone if present
let phone = input.contact_phone || '';
if (phone && !phone.startsWith('+')) {
  phone = '+1' + phone.replace(/\D/g, '');
}

return [{
  json: {
    valid: errors.length === 0,
    errors,
    case_id: input.case_id || input.matter_id || 'matter_' + Math.floor(Math.random() * 90000 + 10000),
    client: input.client,
    description: input.description || '',
    existing_case_type: input.case_type || null,
    contact_phone: phone,
    contact_email: input.contact_email || '',
    source: input.source || 'intake',
    timestamp: new Date().toISOString(),
    firm: 'Greenfield & Associates'
  }
}];

// Parse AI classification and prepare routing data
const caseData = $('Extract Case Details').first().json;
const aiResponse = $input.first().json;

let classification;
try {
  const content = aiResponse.choices?.[0]?.message?.content || '{}';
  classification = JSON.parse(content);
} catch (e) {
  classification = {
    case_type: 'other',
    confidence: 0,
    urgency: 'medium',
    urgency_score: 5,
    reason: 'AI classification failed — manual routing required',
    recommended_attorney: 'A. Chen'
  };
}

return [{
  json: {
    ...caseData,
    ai_classification: classification,
    route_key: classification.case_type,
    requires_human_review: true,
    review_status: 'pending',
    assignment_method: 'ai_recommended_human_approved'
  }
}];
